          </ul>
        </CardContent>
      </Card>
      <Card className="lg:col-span-2">
        <CardHeader icon={Activity}>
          <CardTitle>Patient vitals (edge → fog → cloud)</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-2 mb-4">
            <Label>Patient</Label>
            <Select
